-- Barrios de Manizales enriquecidos (Alcaldía de Manizales, DANE Censo 2019, 4-72).
-- Datos casi estáticos -> se almacenan una vez, no se re-consultan por fetch.
create extension if not exists postgis;
create table if not exists barrios_manizales (
  id int primary key, barrio text not null, id_comuna text, comuna text,
  estrato smallint, poblacion int, codigo_postal text,
  centroid_lng double precision, centroid_lat double precision,
  geom geometry(MultiPolygon,4326)
);
create index if not exists barrios_geom_gix on barrios_manizales using gist(geom);
create index if not exists barrios_barrio_ix on barrios_manizales (barrio);
alter table barrios_manizales enable row level security;
drop policy if exists barrios_public_read on barrios_manizales;
create policy barrios_public_read on barrios_manizales for select to anon, authenticated using (true);

on conflict (id) do nothing;
